def merge_within(pairs):
    if not pairs:
        return []

    merged = sorted(pairs, key=lambda x: x[0])
    result = [merged[0]]

    for start, end in merged[1:]:
        last_start, last_end = result[-1]

        if start <= last_end + 1:
            result[-1] = [last_start, max(last_end, end)]
        else:
            result.append([start, end])

    return result
